// Advanced AI-powered document classification with data extraction
const item = $input.first().json;
const text = item.text || '';

// Initialize document metadata
let docType = 'unknown';
let extractedData = {};
let confidence = 0;

// Invoice Detection & Extraction
if (text.match(/\b(invoice|bill|payment due|total amount)\b/i)) {
    docType = 'invoice';
    confidence = 0.95;

    // Extract invoice number
    const invoiceMatch = text.match(/invoice[\s#:]*([A-Z0-9-]+)/i);
    extractedData.invoiceNumber = invoiceMatch ? invoiceMatch[1] : 'N/A';

    // Extract amount with multiple currency formats
    const amountMatch = text.match(/(?:total|amount|due)[:\s$€£]*([0-9,]+\.?[0-9]{0,2})/i);
    extractedData.amount = amountMatch ? parseFloat(amountMatch[1].replace(/,/g, '')) : 0;

    // Extract vendor name
    const vendorMatch = text.match(/(?:from|vendor|supplier)[:\s]*([A-Z][a-z\s&]+)/i);
    extractedData.vendor = vendorMatch ? vendorMatch[1].trim() : 'Unknown';

    // Extract due date
    const dateMatch = text.match(/due[\s:]*([0-9]{1,2}[\/\-][0-9]{1,2}[\/\-][0-9]{2,4})/i);
    extractedData.dueDate = dateMatch ? dateMatch[1] : null;
}
// Payroll Detection & Extraction
else if (text.match(/\b(payroll|salary|wage|timesheet|hours worked)\b/i)) {
    docType = 'payroll';
    confidence = 0.92;

    // Extract employee ID
    const empMatch = text.match(/(?:employee|emp)[\s#:]*([A-Z0-9-]+)/i);
    extractedData.employeeId = empMatch ? empMatch[1] : 'N/A';

    // Extract hours worked
    const hoursMatch = text.match(/(?:hours|hrs)[\s:]*([0-9]+\.?[0-9]*)/i);
    extractedData.hoursWorked = hoursMatch ? parseFloat(hoursMatch[1]) : 0;

    // Extract pay period
    const periodMatch = text.match(/period[\s:]*([0-9]{1,2}[\/\-][0-9]{1,2}[\s-to-]*[0-9]{1,2}[\/\-][0-9]{1,2})/i);
    extractedData.payPeriod = periodMatch ? periodMatch[1] : null;

    extractedData.amount = 0; // Default for routing logic
}
// Legal Document Detection
else if (text.match(/\b(contract|agreement|NDA|terms and conditions|legal notice)\b/i)) {
    docType = 'legal';
    confidence = 0.88;

    // Extract contract type
    const contractMatch = text.match(/([A-Z][a-z]+)\s+(?:contract|agreement)/i);
    extractedData.contractType = contractMatch ? contractMatch[1] : 'General';

    // Extract parties involved
    const partiesMatch = text.match(/between[\s:]*([A-Z][a-z\s&,]+)\s+and\s+([A-Z][a-z\s&,]+)/i);
    if (partiesMatch) {
        extractedData.party1 = partiesMatch[1].trim();
        extractedData.party2 = partiesMatch[2].trim();
    }

    // Extract effective date
    const effDateMatch = text.match(/effective[\s:]*([0-9]{1,2}[\/\-][0-9]{1,2}[\/\-][0-9]{2,4})/i);
    extractedData.effectiveDate = effDateMatch ? effDateMatch[1] : null;

    extractedData.amount = 0;
}
// Purchase Order Detection
else if (text.match(/\b(purchase order|PO|requisition|procurement)\b/i)) {
    docType = 'purchase_order';
    confidence = 0.90;

    const poMatch = text.match(/(?:PO|purchase order)[\s#:]*([A-Z0-9-]+)/i);
    extractedData.poNumber = poMatch ? poMatch[1] : 'N/A';

    const amountMatch = text.match(/(?:total|amount)[:\s$€£]*([0-9,]+\.?[0-9]{0,2})/i);
    extractedData.amount = amountMatch ? parseFloat(amountMatch[1].replace(/,/g, '')) : 0;
}

// Apply extracted data to item
item.type = docType;
item.confidence = confidence;
item.extractedData = extractedData;
item.amount = extractedData.amount || 0;
item.processedAt = new Date().toISOString();
item.requiresReview = confidence < 0.85;

// Add metadata for tracking
item.wordCount = text.split(/\s+/).length;
item.pageLength = text.length;

return { json: item };

